+/**
+ * Analytics data models for the dashboard feature.
+ *
+ * These types define the shape of analytics data throughout the system:
+ * - Query parameters for filtering/time ranges
+ * - Aggregated metric summaries
+ * - Time series data for charting
+ * - Composite dashboard response
+ *
+ * Design principle: All analytics types are read-only projections over
+ * existing Order and User data. The analytics system does not own any
+ * mutable state — it queries existing repositories and computes
+ * aggregations on the fly (or from a cache, if implemented later).
+ */
+
+import type { OrderStatus } from './order.js';
+
+// ---------------------------------------------------------------------------
+// Query / filter types
+// ---------------------------------------------------------------------------
+
+/**
+ * Granularity for time-series bucketing.
+ */
+export type TimeGranularity = 'hour' | 'day' | 'week' | 'month';
+
+/**
+ * Common query parameters shared by all analytics endpoints.
+ */
+export interface AnalyticsQuery {
+  /** Start of the time range (inclusive). */
+  startDate: Date;
+  /** End of the time range (inclusive). */
+  endDate: Date;
+  /** Bucket size for time-series data. Defaults to 'day'. */
+  granularity?: TimeGranularity;
+}
+
+/**
+ * Query parameters for the metrics endpoint.
+ * Extends AnalyticsQuery with a metric type selector.
+ */
+export interface MetricQuery extends AnalyticsQuery {
+  /** Which metric to retrieve. */
+  metricType: MetricType;
+}
+
+// ---------------------------------------------------------------------------
+// Core metric types
+// ---------------------------------------------------------------------------
+
+/**
+ * Supported metric types that can be queried individually.
+ */
+export type MetricType =
+  | 'orders'
+  | 'revenue'
+  | 'users'
+  | 'average-order-value';
+
+/**
+ * A single point in a time series.
+ */
+export interface TimeSeriesPoint {
+  /** The start of this time bucket. */
+  timestamp: Date;
+  /** The aggregated value for this bucket. */
+  value: number;
+  /** Optional label (e.g., formatted date string). */
+  label?: string;
+}
+
+/**
+ * Summary statistics for a single metric over a time range.
+ */
+export interface MetricSummary {
+  /** Which metric this summary represents. */
+  metricType: MetricType;
+  /** Current value for the queried period. */
+  currentValue: number;
+  /** Value for the equivalent previous period (for comparison). */
+  previousValue: number;
+  /** Percentage change from previous to current period. */
+  changePercent: number;
+  /** Trend direction derived from changePercent. */
+  trend: 'up' | 'down' | 'flat';
+  /** Time series breakdown within the queried period. */
+  timeSeries: TimeSeriesPoint[];
+}
+
+// ---------------------------------------------------------------------------
+// Order-specific analytics
+// ---------------------------------------------------------------------------
+
+/**
+ * Breakdown of orders by their current status.
+ */
+export interface OrderStatusBreakdown {
+  status: OrderStatus;
+  count: number;
+  /** Percentage of total orders in the queried period. */
+  percentage: number;
+}
+
+/**
+ * Revenue analytics with additional breakdowns.
+ */
+export interface RevenueBreakdown {
+  totalRevenue: number;
+  averageOrderValue: number;
+  /** Revenue broken down by order status. */
+  byStatus: Array<{ status: OrderStatus; revenue: number }>;
+}
+
+// ---------------------------------------------------------------------------
+// User-specific analytics
+// ---------------------------------------------------------------------------
+
+/**
+ * Summary of user growth and activity.
+ */
+export interface UserAnalytics {
+  totalUsers: number;
+  newUsersInPeriod: number;
+  /** Users who placed at least one order in the period. */
+  activeUsersInPeriod: number;
+  /** Breakdown by role. */
+  byRole: Array<{ role: string; count: number }>;
+}
+
+// ---------------------------------------------------------------------------
+// Top-level dashboard response
+// ---------------------------------------------------------------------------
+
+/**
+ * The composite response for the dashboard overview endpoint.
+ * Bundles all key metrics into a single payload so the frontend
+ * can render the full dashboard with one request.
+ */
+export interface DashboardData {
+  /** The query that produced this data. */
+  query: AnalyticsQuery;
+  /** High-level metric cards. */
+  metrics: {
+    orders: MetricSummary;
+    revenue: MetricSummary;
+    users: MetricSummary;
+    averageOrderValue: MetricSummary;
+  };
+  /** Order status distribution. */
+  orderStatusBreakdown: OrderStatusBreakdown[];
+  /** Revenue details. */
+  revenueBreakdown: RevenueBreakdown;
+  /** User growth and engagement. */
+  userAnalytics: UserAnalytics;
+  /** When this data was generated (for cache staleness checks). */
+  generatedAt: Date;
+}
+
+// ---------------------------------------------------------------------------
+// API response wrappers
+// ---------------------------------------------------------------------------
+
+/**
+ * Standard envelope for all analytics API responses.
+ * Keeps the response shape consistent and extensible.
+ */
+export interface AnalyticsResponse<T> {
+  success: boolean;
+  data: T;
+  meta: {
+    generatedAt: Date;
+    queryDurationMs: number;
+  };
+}

